import { Component, h, Prop, Element, Listen, State } from '@stencil/core';
import { KEYBOARD_KEYS } from '../../models/keycodes.model';
import { generateRandId } from '../../utils/utils';

@Component({
  tag: 'wdpr-tile-group',
  shadow: true,
})
export class WdprTileGroup {
  @Element() el: HTMLElement;

  @State() private _internalId: string;

  @Prop({ mutable: true, reflect: true }) columns: number = 1;
  @Prop({ mutable: true, reflect: true }) tileGroupId: string;
  @Prop({ attribute: 'a11y-label' }) a11yLabel: string = '';

  componentDidLoad() {
    this._propagateToSlotElements();
  }

  componentWillLoad() {
    this._internalId = this.tileGroupId || `wdpr-tile-group-${generateRandId()}`;
  }

  @Listen('slotchange')
  onSlotChange() {
    this._propagateToSlotElements();
  }

  @Listen('keydown')
  handleKeyDown(ev: KeyboardEvent) {
    if (ev.key == KEYBOARD_KEYS.ESCAPE) {
      ev.preventDefault();
      (document.activeElement as HTMLElement)?.blur();
    }
  }

  @Listen('wdprClick')
  handleTileClick(event: CustomEvent) {
    event.stopImmediatePropagation();
    const clickedTile = event.target as HTMLWdprTileElement;

    if (clickedTile.disabled) return;

    clickedTile.focus();
  }

  private _propagateToSlotElements = () => {
    const slot = this.el.shadowRoot.querySelector('slot');

    if (slot) {
      slot.assignedElements().forEach((el: HTMLWdprTileRowElement) => {
        el.columns = this.columns;
      });
    }
  };

  render() {
    return (
      <div role="group" id={this._internalId} aria-label={this.a11yLabel || 'Tile Group'}>
        <slot></slot>
      </div>
    );
  }
}
